const privateKey = 'YOUR_PRIVATE_KEY';
const fromAddress = web3.eth.accounts.privateKeyToAccount(privateKey).address;

// Function to fetch pending transactions
async function getPendingTransactions() {
  const txs = await web3.eth.getPendingTransactions();
  return txs;
}

// Function to estimate gas price
async function estimateGasPrice() {
  const gasPrice = await web3.eth.getGasPrice();
  return gasPrice;
}

// Function to submit a transaction with higher gas price
async function submitTransactionWithHigherGasPrice(tx) {
  const gasPrice = await estimateGasPrice();
  const newGasPrice = web3.utils.toWei(gasPrice.toString(), 'gwei').toString(10);
  
  tx.gasPrice = newGasPrice;
  tx.from = fromAddress;

  try {
    const signedTx = await web3.eth.accounts.signTransaction(tx, privateKey);
    const receipt = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);
    console.log('Transaction submitted:', receipt.transactionHash);
  } catch (error) {
    console.error('Error submitting transaction:', error);
  }
}

